193	// MinRecycleMaxAttempts is the floor for a recycle lane's attempt count.
194	// A lane must permit at least one attempt; zero would mean "never run
195	// this phase," which is expressed by removing the lane, not by scaling
196	// it to zero.
197	const MinRecycleMaxAttempts = 1
198	
199	// MaxRecycleMaxAttempts is the ceiling. The verify loop is a token-spend
200	// surface (every retry costs money), and the cumulative cost budget is
201	// the primary ceiling; this attempt cap is a coarse second guard rail.
202	// Values past this are almost certainly a typo and would let a single
203	// run grind far past any reasonable retry budget before the cost ceiling
