213	// ApplyRecycleMaxAttemptsPatches mutates reg in place, scaling the
214	// max_attempts on the addressed recycle lanes. It validates each patch
215	// and returns a ValidationError (HTTP 400) for bad input: an unknown
216	// target, a target whose lane does not exist, an out-of-range count, or
217	// a duplicate target in the same request.
218	func ApplyRecycleMaxAttemptsPatches(reg *WorkflowRegister, patches []RecycleMaxAttemptsPatch) error {
219		if len(patches) == 0 {
220			return nil
221		}
222		seen := map[string]struct{}{}
223		for _, patch := range patches {
224			target := strings.TrimSpace(patch.Target)
225			if target == "" {
226				return ValidationError{Message: "recycle_max_attempts entry is missing target"}
227			}
228			if _, dup := seen[target]; dup {
229				return ValidationError{Message: fmt.Sprintf("recycle_max_attempts target %q is repeated", target)}
230			}
231			seen[target] = struct{}{}
232			if patch.MaxAttempts < MinRecycleMaxAttempts || patch.MaxAttempts > MaxRecycleMaxAttempts {
233				return ValidationError{Message: fmt.Sprintf(
234					"recycle_max_attempts target %q max_attempts=%d is out of range [%d, %d]",
235					target, patch.MaxAttempts, MinRecycleMaxAttempts, MaxRecycleMaxAttempts,
236				)}
237			}
238			policy, err := recycleLaneForTarget(reg, target)
239			if err != nil {
240				return err
241			}
242			policy.MaxAttempts = patch.MaxAttempts
243		}
244		return nil
245	}
