8612	// workflow advances past it like a success. The skip is durable in the
8613	// attempt record so projections render the dedicated "skipped" pill.
8614	func (s *Store) StampLatestAttemptSkipped(ctx context.Context, project, runID string) error {
8615		now := time.Now().UTC().Format(time.RFC3339Nano)
8616		_, err := s.pgRuns.PatchPayload(ctx, project, runID, func(raw map[string]any) error {
8617			attempts, _ := raw["attempts"].([]any)
8618			if len(attempts) == 0 {
8619				return fmt.Errorf("run has no attempts to stamp")
8620			}
8621			last, ok := attempts[len(attempts)-1].(map[string]any)
8622			if !ok {
8623				return fmt.Errorf("malformed attempt record")
8624			}
8625			skipped := "skipped"
8626			advance := "advance"
8627			last["conclusion"] = skipped
8628			last["decision"] = advance
8629			last["completed_at"] = now
8630			attempts[len(attempts)-1] = last
8631			raw["attempts"] = attempts
8632			raw["updated_at"] = now
8633			return nil
8634		})
8635		if errors.Is(err, pgstore.ErrRunNotFound) {
8636			return server.ErrNotFound
8637		}
8638		return err
