82	// resolveDispatchRunInputs reconciles the caller-supplied run inputs against
83	// the workflow's declared DispatchInputs. The returned map contains exactly
84	// the declared inputs, populated from the caller's values where present and
85	// from declared defaults otherwise.
86	//
87	// The rules are intentionally strict and symmetrical with the validator:
88	//   - A required input that the caller did not supply and that carries no
89	//     non-empty default is rejected. There is no server-side guess (no
90	//     "default to main", no "fall back to the project's branch") — the
91	//     migration policy forbids fallback defaults, so the dispatcher must
92	//     either declare a Default on the workflow input or supply the value.
93	//   - An undeclared input the caller supplied is rejected. The workflow's
94	//     dispatch_inputs is the contract; sending a key the workflow does not
95	//     reference would silently flow into Run.RunInputs and be untraceable.
96	//
97	// On success the returned map carries only declared keys, with any caller
98	// overrides applied on top of declared defaults.
99	func resolveDispatchRunInputs(declared []DispatchInputSpec, supplied map[string]string) (map[string]string, error) {
100		declaredByName := make(map[string]DispatchInputSpec, len(declared))
