107			}
108		}
109		resolved := make(map[string]string, len(declared))
110		for _, input := range declared {
111			value, hasValue := supplied[input.Name]
112			if hasValue && value != "" {
113				resolved[input.Name] = value
114				continue
115			}
116			if input.Default != "" {
117				resolved[input.Name] = input.Default
118				continue
119			}
120			if input.Required {
121				return nil, fmt.Errorf("inputs.%s is required by the workflow but was not provided and has no default", input.Name)
122			}
123			// Non-required with empty default is rejected at register time, so
124			// reaching here would mean a malformed registration slipped through;
125			// be loud rather than persist an empty substitution.
126			return nil, fmt.Errorf("inputs.%s is declared without a default and is not required; reject as malformed", input.Name)
127		}
128		return resolved, nil
