func launchedNativeJobMap(phase PhaseSpec, launched []string) map[string]string {
	jobs := make(map[string]string, len(launched))
	for i, job := range phase.Jobs {
		if i >= len(launched) {
			break
		}
		if job.ID == "" || launched[i] == "" {
			continue
		}
		jobs[job.ID] = launched[i]
	}
	return jobs
}
