	err = Validate("${{ inputs.nope }} == 'x'", "loc", vars, inputs)
	if err == nil || !strings.Contains(err.Error(), "dispatch_inputs does not declare \"nope\"") {
		t.Fatalf("undeclared inputs ref must fail, got: %v", err)
	}
}

